import{_ as e,a as s}from"./chunks/electron-logo.Be0O4UVs.js";import{_ as o,c as n,o as a,ae as i}from"./chunks/framework.Cqi9LMMK.js";const f=JSON.parse('{"title":"Installation","description":"","frontmatter":{"title":"Installation"},"headers":[],"relativePath":"guide/install.md","filePath":"guide/install.md"}'),r={name:"guide/install.md"};function l(d,t,c,h,p,g){return a(),n("div",null,[...t[0]||(t[0]=[i('<h1 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h1><p>Vue Inspector is available in more than one launch mode so you can use it across environments and browsers.</p><p>The right mode depends on environment constraints, security policy, and how you prefer to work.</p><div class="install-options"><a class="install-option-card" href="./extension"><span class="install-option-icon install-option-icon--brand" aria-hidden="true"><img src="'+e+'" alt="" width="32" height="32" loading="lazy" decoding="async"></span><span class="install-option-body"><span class="install-option-title">Browser extension</span><span class="install-option-desc">Full control inside the browser.</span></span></a><a class="install-option-card" href="./standalone"><span class="install-option-icon install-option-icon--brand" aria-hidden="true"><img src="'+s+'" alt="" width="32" height="32" loading="lazy" decoding="async"></span><span class="install-option-body"><span class="install-option-title">Standalone app</span><span class="install-option-desc">For strict policies and any browser.</span></span></a></div><h2 id="which-one-should-i-pick" tabindex="-1">Which one should I pick? <a class="header-anchor" href="#which-one-should-i-pick" aria-label="Permalink to &quot;Which one should I pick?&quot;">​</a></h2><ul><li><strong>Chrome extension</strong> — when you want persistent access and the full feature set: auto run, DevTools integration, and advanced in-browser workflows.</li><li><strong>Standalone</strong> — when extensions are blocked, enterprise policy applies, or you need a bookmarklet-style launch without installing the extension.</li></ul><hr><h2 id="storage" tabindex="-1">Where settings are stored <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Where settings are stored {#storage}&quot;">​</a></h2><p>Both the <strong>extension</strong> and <strong>standalone</strong> share <strong>one settings profile</strong> for the browser: after you save options, the same values apply on <strong>every site</strong> where you open the inspector. You do not configure per domain separately.</p><p>Only the <strong>storage mechanism</strong> differs: the extension uses Chrome’s storages for the installed component; standalone uses a <strong>separate local store</strong> for the app (no <code>chrome://extensions</code> install), dedicated to that mode.</p><table tabindex="0"><thead><tr><th></th><th><strong>Extension</strong></th><th><strong>Standalone (bookmark)</strong></th></tr></thead><tbody><tr><td><strong>Settings</strong> (options, favorites, site lists, etc.)</td><td>The extension’s <strong>local storage</strong> in the browser profile: data is tied to the installed Vue Inspector build, not a specific tab.</td><td><strong>Dedicated</strong> standalone local storage — same idea, one database for all sites you launch via the bookmark.</td></tr><tr><td><strong>Customize assets</strong> (backgrounds, saved media from Customize and related UI)</td><td>Stored in <strong>browser storage</strong> under the extension context (files live in the profile, not “on the site”).</td><td>Goes into the <strong>same unified</strong> standalone store, subject to its limits (see <a href="/docs/options/customize.html">Customize</a>).</td></tr><tr><td><strong>Across sites</strong></td><td>One settings set for all origins in this browser profile.</td><td>One settings set for all origins: storage is <strong>not</strong> bound to the page origin, so reuse matches the extension.</td></tr></tbody></table><p>For media limits in Customize see <a href="/docs/options/customize.html">Customize</a>.</p><p><strong>Saving and migration:</strong> normal edits in Options <strong>autosave</strong> (with a small debounce). The <strong>extension</strong> mirrors settings in <strong>IndexedDB</strong> and <strong><code>chrome.storage.local</code></strong>; <strong>standalone</strong> keeps a snapshot in its <strong>central KV store</strong> (IndexedDB), with media stored separately under a size cap. <strong>Export / Import / Reset</strong> in General produce a JSON file and a full reset; what differs between modes in export/import is covered in <a href="/docs/options/settings_management.html">Settings management</a>.</p>',13)])])}const b=o(r,[["render",l]]);export{f as __pageData,b as default};
